            "solution": "public String removeWhitespaces(String input) { \n    StringBuilder result = new StringBuilder(); \n    for (int i = 0; i < input.length(); i++) { \n        if (input.charAt(i) != ' ') { \n            result.append(input.charAt(i)); \n        } \n    } \n    return result.toString(); \n}",
