            "solution": "public void iterateList(List<Integer> list) { \n    // Using for-loop \n    for (int i = 0; i < list.size(); i++) { \n        System.out.println(list.get(i)); \n    } \n    // Using while-loop \n    int j = 0; \n    while (j < list.size()) { \n        System.out.println(list.get(j)); \n        j++; \n    } \n    // Using advanced for-loop \n    for (int item : list) { \n        System.out.println(item); \n    }",
