            "title": "Write a Java Program to find the second-highest number in an array.",
            "problem": "Write a Java Program to find the second-highest number in an array.",
            "solution": "public int secondHighest(int[] nums) { \n    int highest = Integer.MIN_VALUE, secondHighest = Integer.MIN_VALUE; \n    for (int num : nums) { \n        if (num > highest) { \n            secondHighest = highest; \n            highest = num; \n        } else if (num > secondHighest && num != highest) { \n            secondHighest = num; \n        } \n    } \n    return secondHighest; \n}",
